const express = require('express');
const cors = require('cors');
const path = require('path');
const fs = require('fs');
const initSqlJs = require('sql.js');

const app = express();
const PORT = process.env.PORT || 3000;
const HOST = '0.0.0.0';

app.use(cors());
app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));

// Создание папок
const dirs = ['public/audio', 'public/images/avatars', 'public/images/maps'];
dirs.forEach(dir => {
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
});

// ---------- База данных (sql.js) ----------
let db = null;
const DB_PATH = path.join(__dirname, 'database.sqlite');

function dbAll(sql, params = []) {
    const stmt = db.prepare(sql);
    stmt.bind(params);
    const rows = [];
    while (stmt.step()) {
        const row = {};
        const cols = stmt.getColumnNames();
        const values = stmt.get();
        cols.forEach((col, i) => row[col] = values[i]);
        rows.push(row);
    }
    stmt.free();
    return rows;
}

function dbGet(sql, params = []) {
    const rows = dbAll(sql, params);
    return rows.length > 0 ? rows[0] : null;
}

function dbRun(sql, params = []) {
    db.run(sql, params);
    saveDatabase();
}

function saveDatabase() {
    const data = db.export();
    const buffer = Buffer.from(data);
    fs.writeFileSync(DB_PATH, buffer);
}

async function initDatabase() {
    const SQL = await initSqlJs();
    if (fs.existsSync(DB_PATH)) {
        const buffer = fs.readFileSync(DB_PATH);
        db = new SQL.Database(buffer);
    } else {
        db = new SQL.Database();
    }

    db.run(`CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        login TEXT UNIQUE,
        password TEXT,
        avatar TEXT DEFAULT 'default.png',
        total_xp INTEGER DEFAULT 0,
        current_level INTEGER DEFAULT 1
    )`);

    db.run(`CREATE TABLE IF NOT EXISTS progress (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER,
        route_id TEXT,
        route_name TEXT,
        progress_percent INTEGER,
        completion_awarded INTEGER DEFAULT 0,
        FOREIGN KEY(user_id) REFERENCES users(id)
    )`);

    db.run(`CREATE TABLE IF NOT EXISTS favorites (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER,
        route_id TEXT,
        point_index INTEGER,
        point_title TEXT,
        point_panorama TEXT,
        FOREIGN KEY(user_id) REFERENCES users(id)
    )`);

    saveDatabase();
}

// ---------- Константы ----------
const XP_PER_LEVEL = 120;
const THEME_XP_MULTIPLIER = {
    kazakhstan: 1.0,
    georgia: 1.15,
    silk: 1.25
};
const DIFFICULTY_XP_MULTIPLIER = {
    'Лёгкий': 1.0,
    'Средний': 1.2,
    'Сложный': 1.4
};

function findRouteMeta(routeId) {
    for (const [themeId, routes] of Object.entries(ROUTES)) {
        const route = routes.find((item) => item.id === routeId);
        if (route) return { route, themeId };
    }
    return null;
}

function clampPercent(value) {
    const n = Number(value);
    if (!Number.isFinite(n)) return 0;
    return Math.max(0, Math.min(100, Math.round(n)));
}

function calcRouteXp(deltaPercent, route, themeId) {
    const themeCoef = THEME_XP_MULTIPLIER[themeId] || 1.0;
    const difficultyCoef = DIFFICULTY_XP_MULTIPLIER[route.difficulty] || 1.0;
    const pointsCoef = Math.max(1, (route.pointsData?.length || 7) / 7);
    const raw = deltaPercent * 0.9 * themeCoef * difficultyCoef * pointsCoef;
    return Math.max(0, Math.round(raw));
}

