// ---------- API ----------
app.get('/api/ping', (req, res) => res.json({ status: 'ok' }));
app.get('/api/themes', (req, res) => res.json(THEMES));

app.get('/api/routes/:themeId', (req, res) => {
    const routes = ROUTES[req.params.themeId] || [];
    res.json(routes.map(r => ({ id: r.id, name: r.name, description: r.description, difficulty: r.difficulty, duration: r.duration, points: r.pointsData.length })));
});

app.get('/api/route/:routeId', (req, res) => {
    const route = Object.values(ROUTES).flat().find(r => r.id === req.params.routeId);
    route ? res.json(route) : res.status(404).json({ error: 'Маршрут не найден' });
});

app.post('/api/auth', (req, res) => {
    const { login, password } = req.body;
    try {
        let user = dbGet('SELECT * FROM users WHERE login = ?', [login]);
        if (user) {
            if (user.password === password) res.json({ success: true, message: 'С возвращением!', user });
            else res.json({ success: false, message: 'Неверный пароль' });
        } else {
            dbRun('INSERT INTO users (login, password) VALUES (?, ?)', [login, password]);
            user = dbGet('SELECT * FROM users WHERE login = ?', [login]);
            res.json({ success: true, message: 'Новое имя в летописи!', user });
        }
    } catch (err) { res.status(500).json({ error: err.message }); }
});

app.get('/api/progress/:userId', (req, res) => {
    try {
        const rows = dbAll('SELECT route_id, route_name, progress_percent FROM progress WHERE user_id = ?', [req.params.userId]);
        res.json(rows || []);
    } catch (err) { res.status(500).json({ error: err.message }); }
});

app.post('/api/progress', (req, res) => {
    const { userId, routeId } = req.body;
    const safePercent = clampPercent(req.body.percent);
    const routeMeta = findRouteMeta(routeId);
    if (!routeMeta) return res.status(400).json({ success: false, error: 'Некорректный маршрут' });

    const routeName = routeMeta.route.name;
    try {
        const row = dbGet('SELECT id, progress_percent, completion_awarded FROM progress WHERE user_id = ? AND route_id = ?', [userId, routeId]);
        const prevPercent = row ? Number(row.progress_percent) || 0 : 0;
        if (safePercent > prevPercent + 40) return res.status(400).json({ success: false, error: 'Подозрительный скачок прогресса' });

        const nextPercent = Math.max(prevPercent, safePercent);
        const deltaPercent = Math.max(0, nextPercent - prevPercent);
        let xpGained = calcRouteXp(deltaPercent, routeMeta.route, routeMeta.themeId);

        const completionAlreadyAwarded = row ? Number(row.completion_awarded) === 1 : false;
        const completionBonus = (!completionAlreadyAwarded && nextPercent === 100) ? Math.round(35 * (THEME_XP_MULTIPLIER[routeMeta.themeId] || 1)) : 0;
        xpGained += completionBonus;

        if (row) {
            dbRun('UPDATE progress SET progress_percent = ?, route_name = ?, completion_awarded = ? WHERE id = ?', [nextPercent, routeName, completionAlreadyAwarded || completionBonus > 0 ? 1 : 0, row.id]);
        } else {
            dbRun('INSERT INTO progress (user_id, route_id, route_name, progress_percent, completion_awarded) VALUES (?, ?, ?, ?, ?)', [userId, routeId, routeName, nextPercent, completionBonus > 0 ? 1 : 0]);
        }

        if (xpGained <= 0) return res.json({ success: true, xpGained: 0, percent: nextPercent });

        const user = dbGet('SELECT total_xp FROM users WHERE id = ?', [userId]);
        if (!user) return res.status(500).json({ success: false, error: 'Пользователь не найден' });

        const currentXp = Number(user.total_xp) || 0;
        const newTotalXp = currentXp + xpGained;
        const newLevel = Math.floor(newTotalXp / XP_PER_LEVEL) + 1;
        dbRun('UPDATE users SET total_xp = ?, current_level = ? WHERE id = ?', [newTotalXp, newLevel, userId]);
        res.json({ success: true, xpGained, percent: nextPercent });
    } catch (err) { res.status(500).json({ error: err.message }); }
});

app.get('/api/favorites/:userId', (req, res) => {
    try { res.json(dbAll('SELECT * FROM favorites WHERE user_id = ?', [req.params.userId]) || []); }
    catch (err) { res.status(500).json({ error: err.message }); }
});

app.post('/api/favorites', (req, res) => {
    const { userId, routeId, pointIndex, pointTitle, pointPanorama } = req.body;
    try {
        const row = dbGet('SELECT id FROM favorites WHERE user_id = ? AND route_id = ? AND point_index = ?', [userId, routeId, pointIndex]);
        if (row) {
            dbRun('DELETE FROM favorites WHERE id = ?', [row.id]);
            res.json({ success: true, action: 'removed' });
        } else {
            dbRun('INSERT INTO favorites (user_id, route_id, point_index, point_title, point_panorama) VALUES (?, ?, ?, ?, ?)', [userId, routeId, pointIndex, pointTitle, pointPanorama]);
            res.json({ success: true, action: 'added' });
        }
    } catch (err) { res.status(500).json({ error: err.message }); }
});

app.post('/api/avatar', (req, res) => {
    try { dbRun('UPDATE users SET avatar = ? WHERE id = ?', [req.body.avatar, req.body.userId]); res.json({ success: true }); }
    catch (err) { res.status(500).json({ error: err.message }); }
});

app.get('/api/user/:userId', (req, res) => {
    try {
        const user = dbGet('SELECT id, login, avatar, total_xp, current_level FROM users WHERE id = ?', [req.params.userId]);
        if (user) { user.total_xp = Number(user.total_xp) || 0; user.current_level = Number(user.current_level) || 1; }
        res.json(user);
    } catch (err) { res.status(500).json({ error: err.message }); }
});

app.patch('/api/user/:userId/login', (req, res) => {
    const userId = Number(req.params.userId);
    const newLogin = String(req.body?.login || '').trim();
    if (!userId) return res.status(400).json({ success: false, message: 'Некорректный пользователь' });
    if (newLogin.length < 3 || newLogin.length > 24) return res.status(400).json({ success: false, message: 'Ник должен быть от 3 до 24 символов' });
    try {
        if (dbGet('SELECT id FROM users WHERE login = ? AND id != ?', [newLogin, userId])) return res.status(409).json({ success: false, message: 'Такой ник уже занят' });
        dbRun('UPDATE users SET login = ? WHERE id = ?', [newLogin, userId]);
        const updatedUser = dbGet('SELECT id, login, avatar, total_xp, current_level FROM users WHERE id = ?', [userId]);
        res.json({ success: true, message: 'Ник обновлён', user: updatedUser });
    } catch (err) { res.status(500).json({ error: err.message }); }
});

// Старт
initDatabase()
    .then(() => app.listen(PORT, HOST, () => console.log(`🚀 Сервер запущен на http://localhost:${PORT}`)))
    .catch(err => { console.error('Ошибка инициализации БД:', err); process.exit(1); });